#include <stdio.h>
#include <stdlib.h>

typedef struct Edge {int to; int next;} Edge;

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        int *head = (int*)malloc((N+1)*sizeof(int));
        for (int i=1;i<=N;i++) head[i] = -1;
        Edge *edges = (Edge*)malloc((2*M)*sizeof(Edge));
        int ecnt = 0;
        for (int i=0;i<M;i++) {
            int u,v; scanf("%d %d", &u, &v);
            edges[ecnt].to = v; edges[ecnt].next = head[u]; head[u] = ecnt++;
            edges[ecnt].to = u; edges[ecnt].next = head[v]; head[v] = ecnt++;
        }
        char *vis = (char*)calloc(N+1, sizeof(char));
        int *stack = (int*)malloc((N+1)*sizeof(int));
        int *parent = (int*)malloc((N+1)*sizeof(int));
        int found = 0;
        for (int start=1; start<=N && !found; ++start) {
            if (vis[start]) continue;
            int top = 0; stack[top++] = start; parent[start] = -1; vis[start]=1;
            while (top && !found) {
                int u = stack[--top];
                for (int e=head[u]; e!=-1; e=edges[e].next) {
                    int v = edges[e].to;
                    if (!vis[v]) {
                        vis[v]=1; parent[v]=u; stack[top++] = v;
                    } else if (v != parent[u]) {
                        found = 1; break;
                    }
                }
            }
        }
        printf(found ? "YES\n" : "NO\n");
        free(head); free(edges); free(vis); free(stack); free(parent);
    }
    return 0;
}

