import sys

def dfs(u, parent, g, visited):
    visited[u] = True
    for v in g[u]:
        if not visited[v]:
            if dfs(v, u, g, visited):
                return True
        elif v != parent:
            return True
    return False

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        g = [[] for _ in range(N)]
        for _ in range(M):
            u = int(next(it)) - 1
            v = int(next(it)) - 1
            g[u].append(v)
            g[v].append(u)
        visited = [False]*N
        has_cycle = False
        for i in range(N):
            if not visited[i]:
                if dfs(i, -1, g, visited):
                    has_cycle = True
                    break
        out_lines.append('YES' if has_cycle else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

