let outputs = [];
function dfs(u, parent, graph, visited) {
  const stack = [{node: u, parent}];
  while (stack.length) {
    const {node, parent: p} = stack.pop();
    if (visited[node]) continue;
    visited[node] = true;
    for (const v of graph[node]) {
      if (!visited[v]) {
        stack.push({node: v, parent: node});
      } else if (v !== p) {
        return true;
      }
    }
  }
  return false;
}
